  ('police-b20a8cf8-moex-00434', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '關於儀器應用於物證之鑑識，下列敘述何者正確？①原子吸收光譜儀（AAS）可用非破壞性之方', '["氣相層析質譜儀（GC/MS）之質譜儀（MS）係用來將化合物檢體 電漿化", "掃描式電子顯微鏡/X光能譜儀（SEM/EDX）係使用電磁透鏡聚焦電子束以分析檢體", "拉曼儀器（Ramanspectroscopy）可用來檢測假酒中之甲醇成分  ⑤操作FTIR（Fourier-transform infraredspectroscopy）儀器時，可加入KBr藥品與待測固態樣品混合，經打錠後再上機實驗之", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00435', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '關於物證之分析敘述，是否為人類毛髮，可藉由指標值①辨識之；現場是否有血跡的存在，可藉', '["進行氧化還原反應後，發出何種色光", "以辨識之", "、", "、"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00436', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '使用電解法重現金屬物面之磨除字跡時，係將電源供應器的①接在金屬樣本；而②接金屬夾以夾', '["在該金屬面上反覆擦拭以重現字跡", "、", "、", "分別為下列何者？"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00437', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '關於潛伏指紋顯現試劑之適用物面特性，以及該試劑所檢測之指紋殘跡成分物質，請選出正確之', '["寧海德林法（ninhydrin）：非吸水透氣（non-porous）物面，胺基酸", "物理顯現法（physical developer）：曾經濕過之吸水透氣（porous）物面，油脂", "微粒子懸浮液法（SPR）：濕性之非 吸水透氣物面，油脂", "DFO：吸水透氣物面，胺基酸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00438', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '被子彈擊中之玻璃裂痕如下圖，請問該三發子彈射入口（a、b、c）形成之先後順序？ (a) (b) (c)', '["a、b、c", "b、a、c", "c、b、a", "b、c、a"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00439', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '關於毒品的檢驗方法與常用術語，下列何者正確？①攜帶式拉曼（Raman）儀器可做為現場初篩', '["免疫層析分析法（immunochromatographictest）可用以確認毒品類別（如嗎啡、大 麻、安非他命及搖頭丸等）", "質譜術（massspectrometry）可使用於現場初篩毒品", "「燕窩」 是指純度高之毒品  ⑤「海角七號」是指車手送貨  ⑥「開桶」是指從血管注射毒品", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00440', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '「刑事生物識別術（forensic biometrics）」之標記（marker）可區分為兩類別：生理性 （physiological）與行為性（behavioral）。下列那些是屬於生理性識別（physiologicalbiometrics）', '["指紋（fingerprints）", "手（hand）", "虹膜（iris）", "視網膜（retina） ⑤聲音（voice）  ⑥臉部特徵掃描（facialscans）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00441', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '關於物證分析之學理敘述，下列何者正確？①「回退效應（drawbackeffect）」：近距離射擊時，', '["「遮障效應（maskeffect）」：使用高能可見光線照 射物證，其產生之螢光被該高能可見光蓋掉之情形", "「CSI效應（effect）」：犯罪題材之影視 節目對於鑑識科學功效之描繪過分誇大而造成公眾之認知錯誤", "「個異性原則（principle of individuality）」：物物皆有所不同，分辨不出兩物之間的差異，可確認為係相同來源", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00442', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '某酒駕駕駛人之呼氣酒測值為 0.75 mg/L，該值可依循①定律而換算成血液酒精濃度之值為②%', '["、", "分別為下列何者？", "", "亨利定律（Henry’sLaw）"]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "8a54e35acb16", "answer_pdf_sha1": "a0399b96f964", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
